// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title OpBNBYieldTracker
 * @notice Deploy on **opBNB** for high-frequency yield snapshots, heartbeats, and epoch aggregation.
 *         A relayer reads events and calls `YieldUpdateMirror` on BSC (`mirrorToSettlementLayer`).
 *         This contract is intentionally storage-light: hashes and counters on L2, evidence in Greenfield.
 */
contract OpBNBYieldTracker is AccessControl {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant SEQUENCER_ROLE = keccak256("SEQUENCER_ROLE");

    uint32 public activeOpenEpoch;
    uint32 public finalizedEpoch;

    struct Snapshot {
        uint256 yieldEstimateWad;
        uint256 realizedYieldWad;
        uint8 proofFreshnessBps;
        uint8 confidenceScore;
        uint64 observedAt;
        bytes32 storageRef;
        bytes32 hashCommitment;
    }

    mapping(uint32 => mapping(uint256 => Snapshot)) private _epochSnapshots;
    mapping(uint256 => uint32) public lastDeviceEpoch;

    event YieldSnapshotSubmitted(
        uint256 indexed deviceKey,
        uint32 indexed epochId,
        uint256 yieldEstimateWad,
        uint256 realizedYieldWad,
        uint8 proofFreshnessBps,
        uint8 confidenceScore,
        uint64 observedAt,
        bytes32 storageRef,
        bytes32 hashCommitment
    );
    event ProofHeartbeat(uint256 indexed deviceKey, uint32 indexed epochId, uint64 timestamp);
    event EpochOpened(uint32 indexed epochId, uint256 timestamp);
    event EpochFinalized(uint32 indexed epochId, bytes32 aggregateHash, uint256 timestamp);
    event SnapshotRejected(uint256 indexed deviceKey, uint32 indexed epochId, string reason);

    error WrongChain();
    error EpochClosed();

    constructor(address admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(OPERATOR_ROLE, admin);
        _grantRole(SEQUENCER_ROLE, admin);
    }

    /// @dev Optional guard: set `enforceChainId` to expected opBNB id in production.
    uint256 public enforceChainId;
    bool public chainEnforcement;

    function setChainEnforcement(bool on, uint256 expectedChainId) external onlyRole(DEFAULT_ADMIN_ROLE) {
        chainEnforcement = on;
        enforceChainId = expectedChainId;
    }

    function _assertChain() internal view {
        if (!chainEnforcement) return;
        if (block.chainid != enforceChainId) revert WrongChain();
    }

    function beginOpenEpoch(uint32 epochId) external onlyRole(SEQUENCER_ROLE) {
        _assertChain();
        activeOpenEpoch = epochId;
        emit EpochOpened(epochId, block.timestamp);
    }

    /// @param deviceKey Usually the BSC `HardwareNFT` tokenId carried in the cross-chain payload.
    function submitYieldSnapshot(
        uint256 deviceKey,
        uint32 epochId,
        uint256 yieldEstimateWad,
        uint256 realizedYieldWad,
        uint8 proofFreshnessBps,
        uint8 confidenceScore,
        uint64 observedAt,
        bytes32 storageRef,
        bytes32 hashCommitment
    ) external onlyRole(OPERATOR_ROLE) {
        _assertChain();
        if (epochId != activeOpenEpoch) revert EpochClosed();
        if (hashCommitment == bytes32(0)) {
            emit SnapshotRejected(deviceKey, epochId, "zero_commitment");
            return;
        }

        _epochSnapshots[epochId][deviceKey] = Snapshot({
            yieldEstimateWad: yieldEstimateWad,
            realizedYieldWad: realizedYieldWad,
            proofFreshnessBps: proofFreshnessBps,
            confidenceScore: confidenceScore,
            observedAt: observedAt,
            storageRef: storageRef,
            hashCommitment: hashCommitment
        });
        lastDeviceEpoch[deviceKey] = epochId;

        emit YieldSnapshotSubmitted(
            deviceKey,
            epochId,
            yieldEstimateWad,
            realizedYieldWad,
            proofFreshnessBps,
            confidenceScore,
            observedAt,
            storageRef,
            hashCommitment
        );
    }

    function submitProofHeartbeat(uint256 deviceKey, uint32 epochId) external onlyRole(OPERATOR_ROLE) {
        _assertChain();
        emit ProofHeartbeat(deviceKey, epochId, uint64(block.timestamp));
    }

    function finalizeUpdateEpoch(uint32 epochId, bytes32 aggregateHash) external onlyRole(SEQUENCER_ROLE) {
        _assertChain();
        if (epochId != activeOpenEpoch) revert EpochClosed();
        finalizedEpoch = epochId;
        emit EpochFinalized(epochId, aggregateHash, block.timestamp);
    }

    function getSnapshot(uint32 epochId, uint256 deviceKey) external view returns (Snapshot memory) {
        return _epochSnapshots[epochId][deviceKey];
    }
}

project/contracts/opbnb/YieldEpochAggreg.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title YieldEpochAggregator
 * @notice Deploy on opBNB: high-frequency device samples roll into epoch-scoped aggregates.
 *         Canonical lending state stays on BSC; relayers read aggregates/events and push compact snapshots to `OracleConsumer` on BSC.
 *
 * Gas: single SSTORE-heavy accumulator per device per epoch; no unbounded iteration on-chain.
 */
contract YieldEpochAggregator is AccessControl {
    bytes32 public constant SAMPLE_SUBMITTER_ROLE = keccak256("SAMPLE_SUBMITTER_ROLE");

    /// @notice Epoch length in seconds (e.g. 1 hours).
    uint64 public epochDuration;
    uint64 public immutable deployedAt;

    struct EpochAccumulator {
        uint64 epochId;
        uint128 yieldSum;
        uint64 sampleCount;
        uint64 uptimeSumBps;
        /// @notice Minimum confidence seen this epoch (0–10000 bps semantics, protocol-defined).
        uint16 minConfidenceBps;
        bool initialized;
    }

    mapping(uint256 => EpochAccumulator) internal _acc;

    event EpochDurationUpdated(uint64 previous, uint64 next);
    event SampleRecorded(
        uint256 indexed nftId,
        uint64 indexed epochId,
        uint128 yieldSample,
        uint32 uptimeBps,
        uint16 confidenceBps
    );

    error ZeroDuration();

    constructor(uint64 _epochDuration) {
        if (_epochDuration == 0) revert ZeroDuration();
        epochDuration = _epochDuration;
        deployedAt = uint64(block.timestamp);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(SAMPLE_SUBMITTER_ROLE, msg.sender);
    }

    function setEpochDuration(uint64 d) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (d == 0) revert ZeroDuration();
        emit EpochDurationUpdated(epochDuration, d);
        epochDuration = d;
    }

    function currentEpochId() public view returns (uint64) {
        return uint64(block.timestamp / uint256(epochDuration));
    }

    /// @dev Resets accumulator when epoch rolls forward.
    function recordSample(uint256 nftId, uint128 yieldSample, uint32 uptimeBps, uint16 confidenceBps)
        external
        onlyRole(SAMPLE_SUBMITTER_ROLE)
    {
        require(uptimeBps <= 10_000, "uptime");
        uint64 eid = currentEpochId();
        EpochAccumulator storage a = _acc[nftId];
        if (!a.initialized || a.epochId != eid) {
            a.epochId = eid;
            a.yieldSum = 0;
            a.sampleCount = 0;
            a.uptimeSumBps = 0;
            a.minConfidenceBps = type(uint16).max;
            a.initialized = true;
        }
        a.yieldSum += yieldSample;
        a.sampleCount += 1;
        a.uptimeSumBps += uptimeBps;
        if (confidenceBps < a.minConfidenceBps) {
            a.minConfidenceBps = confidenceBps;
        }
        emit SampleRecorded(nftId, eid, yieldSample, uptimeBps, confidenceBps);
    }

    /// @notice Average yield and uptime for the accumulator’s epoch (0 if no samples).
    function getEpochAggregate(uint256 nftId)
        external
        view
        returns (
            uint64 epochId,
            uint256 avgYield,
            uint256 avgUptimeBps,
            uint16 minConfidenceBps,
            uint64 sampleCount
        )
    {
        EpochAccumulator storage a = _acc[nftId];
        epochId = a.epochId;
        sampleCount = a.sampleCount;
        if (sampleCount == 0) {
            return (epochId, 0, 0, 0, 0);
        }
        avgYield = uint256(a.yieldSum) / uint256(sampleCount);
        avgUptimeBps = uint256(a.uptimeSumBps) / uint256(sampleCount);
        minConfidenceBps = a.minConfidenceBps == type(uint16).max ? uint16(0) : a.minConfidenceBps;
    }
}

project/contracts/OracleConsumer.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import "./interfaces/ILendingPoolBnb.sol";
import "./HardwareNFT.sol";

/**
 * @title OracleConsumer
 * @notice BSC settlement consumer: validates compact L2/off-chain snapshots, enforces replay and staleness guards,
 *         optional Greenfield content-hash alignment with `HardwareNFT`, then batches collateral updates on `LendingPool`.
 *
 * Flow: device / opBNB `YieldEpochAggregator` → relayer → `applySnapshotBatch` → `LendingPool`.
 * Set `LendingPool.setOracle(address(this))` so only this contract may push priced collateral.
 */
contract OracleConsumer is AccessControl, EIP712 {
    using ECDSA for bytes32;

    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");
    bytes32 public constant SNAPSHOT_SIGNER_ROLE = keccak256("SNAPSHOT_SIGNER_ROLE");

    bytes32 private constant SNAPSHOT_TYPEHASH = keccak256(
        "Snapshot(uint256 nftId,uint256 collateralWad,uint256 observedAt,uint64 epochId,uint16 confidenceBps,bytes32 greenfieldContentHash,uint64 sourceChainId,uint256 nonce)"
    );

    ILendingPoolBnb public lendingPool;
    HardwareNFT public hardwareNFT;

    uint64 public expectedSourceChainId;
    uint256 public maxSnapshotAgeSeconds;
    uint16 public minConfidenceBps;
    bool public strictGreenfieldHashMatch;
    /// @notice If snapshot is older than this fraction of `maxSnapshotAgeSeconds`, apply haircut (still must be within max age).
    uint16 public freshnessHaircutThresholdBps;
    uint16 public staleFallbackHaircutBps;

    mapping(uint256 => uint256) public snapshotNonce;
    mapping(uint256 => uint64) public lastAppliedEpoch;
    mapping(uint256 => uint256) public lastGoodCollateralWad;

    struct Snapshot {
        uint256 nftId;
        uint256 collateralWad;
        uint256 observedAt;
        uint64 epochId;
        uint16 confidenceBps;
        bytes32 greenfieldContentHash;
        uint64 sourceChainId;
        uint256 nonce;
        bytes signature;
    }

    event LendingPoolUpdated(address indexed pool);
    event HardwareNFTUpdated(address indexed nft);
    event SourceChainUpdated(uint64 chainId);
    event SnapshotPolicyUpdated(uint256 maxAge, uint16 minConfidence, bool strictHash, uint16 freshnessThreshBps, uint16 staleHaircutBps);
    event SnapshotApplied(uint256 indexed nftId, uint256 collateralWad, uint64 epochId, bytes32 greenfieldContentHash);
    event SnapshotSkipped(uint256 indexed nftId, string reason);

    error ZeroAddress();
    error DuplicateNftInBatch();

    constructor(
        address _lendingPool,
        address _hardwareNFT,
        uint64 _expectedSourceChainId,
        uint256 _maxSnapshotAgeSeconds,
        uint16 _minConfidenceBps
    ) EIP712("MachineFi OracleConsumer", "1") {
        if (_lendingPool == address(0) || _hardwareNFT == address(0)) revert ZeroAddress();
        lendingPool = ILendingPoolBnb(_lendingPool);
        hardwareNFT = HardwareNFT(_hardwareNFT);
        expectedSourceChainId = _expectedSourceChainId;
        maxSnapshotAgeSeconds = _maxSnapshotAgeSeconds;
        minConfidenceBps = _minConfidenceBps;
        staleFallbackHaircutBps = 9500;
        freshnessHaircutThresholdBps = 8000;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(RELAYER_ROLE, msg.sender);
        _grantRole(SNAPSHOT_SIGNER_ROLE, msg.sender);
    }

    function setLendingPool(address p) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (p == address(0)) revert ZeroAddress();
        lendingPool = ILendingPoolBnb(p);
        emit LendingPoolUpdated(p);
    }

    function setHardwareNFT(address n) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (n == address(0)) revert ZeroAddress();
        hardwareNFT = HardwareNFT(n);
        emit HardwareNFTUpdated(n);
    }

    function setExpectedSourceChainId(uint64 id) external onlyRole(DEFAULT_ADMIN_ROLE) {
        expectedSourceChainId = id;
        emit SourceChainUpdated(id);
    }

    function setSnapshotPolicy(
        uint256 _maxAge,
        uint16 _minConfidence,
        bool _strictGreenfield,
        uint16 _freshnessHaircutThresholdBps,
        uint16 _staleHaircutBps
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_staleHaircutBps <= 10_000 && _freshnessHaircutThresholdBps <= 10_000, "bps");
        maxSnapshotAgeSeconds = _maxAge;
        minConfidenceBps = _minConfidence;
        strictGreenfieldHashMatch = _strictGreenfield;
        freshnessHaircutThresholdBps = _freshnessHaircutThresholdBps;
        staleFallbackHaircutBps = _staleHaircutBps;
        emit SnapshotPolicyUpdated(_maxAge, _minConfidence, _strictGreenfield, _freshnessHaircutThresholdBps, _staleHaircutBps);
    }

    function _greenfieldHash(uint256 nftId) internal view returns (bytes32) {
        return hardwareNFT.proofContentHash(nftId);
    }

    function _authorizedSigner(address signer) internal view returns (bool) {
        return hasRole(RELAYER_ROLE, signer) || hasRole(SNAPSHOT_SIGNER_ROLE, signer);
    }

    function _validate(
        Snapshot calldata s,
        uint256 expectedNonce
    ) internal view returns (bool ok, uint256 collateralOut, string memory reason) {
        if (s.sourceChainId != expectedSourceChainId) return (false, 0, "sourceChain");
        if (s.observedAt > block.timestamp) return (false, 0, "future");
        if (block.timestamp > s.observedAt + maxSnapshotAgeSeconds) return (false, 0, "stale");
        if (s.confidenceBps < minConfidenceBps) return (false, 0, "confidence");
        if (s.nonce != expectedNonce) return (false, 0, "nonce");
        if (s.epochId < lastAppliedEpoch[s.nftId]) return (false, 0, "epoch");

        if (s.signature.length > 0) {
            bytes32 structHash = keccak256(
                abi.encode(
                    SNAPSHOT_TYPEHASH,
                    s.nftId,
                    s.collateralWad,
                    s.observedAt,
                    s.epochId,
                    s.confidenceBps,
                    s.greenfieldContentHash,
                    s.sourceChainId,
                    s.nonce
                )
            );
            bytes32 digest = _hashTypedDataV4(structHash);
            address signer = digest.recover(s.signature);
            if (!_authorizedSigner(signer)) return (false, 0, "sig");
        } else if (!hasRole(RELAYER_ROLE, msg.sender)) {
            return (false, 0, "relayer");
        }

        bytes32 onChainHash = _greenfieldHash(s.nftId);
        if (strictGreenfieldHashMatch && s.greenfieldContentHash != bytes32(0) && onChainHash != bytes32(0)) {
            if (onChainHash != s.greenfieldContentHash) return (false, 0, "greenfield");
        }

        uint256 col = s.collateralWad;
        uint256 age = block.timestamp - s.observedAt;
        uint256 thresh = (uint256(maxSnapshotAgeSeconds) * uint256(freshnessHaircutThresholdBps)) / 10_000;
        if (age > thresh) {
            col = (col * uint256(staleFallbackHaircutBps)) / 10_000;
        }

        return (true, col, "");
    }

    function applySnapshot(Snapshot calldata s) external onlyRole(RELAYER_ROLE) {
        uint256 expected = snapshotNonce[s.nftId];
        (bool ok, uint256 appliedCol, string memory reason) = _validate(s, expected);
        if (!ok) {
            emit SnapshotSkipped(s.nftId, reason);
            return;
        }
        (uint256 debt, , , , ) = lendingPool.getPosition(s.nftId);
        if (debt == 0) {
            emit SnapshotSkipped(s.nftId, "noPosition");
            return;
        }

        lendingPool.updateCollateralValue(s.nftId, appliedCol);

        unchecked {
            snapshotNonce[s.nftId]++;
        }
        lastAppliedEpoch[s.nftId] = s.epochId;
        lastGoodCollateralWad[s.nftId] = appliedCol;

        emit SnapshotApplied(s.nftId, appliedCol, s.epochId, s.greenfieldContentHash);
    }

    function applySnapshotBatch(Snapshot[] calldata snaps) external onlyRole(RELAYER_ROLE) {
        uint256 n = snaps.length;
        for (uint256 i; i < n; ++i) {
            for (uint256 j = i + 1; j < n; ++j) {
                if (snaps[i].nftId == snaps[j].nftId) revert DuplicateNftInBatch();
            }
        }

        uint256[] memory ids = new uint256[](n);
        uint256[] memory cols = new uint256[](n);
        uint256 k;

        for (uint256 i; i < n; ++i) {
            Snapshot calldata s = snaps[i];
            uint256 expected = snapshotNonce[s.nftId];
            (bool ok, uint256 appliedCol, string memory reason) = _validate(s, expected);
            if (!ok) {
                emit SnapshotSkipped(s.nftId, reason);
                continue;
            }
            (uint256 debt, , , , ) = lendingPool.getPosition(s.nftId);
            if (debt == 0) {
                emit SnapshotSkipped(s.nftId, "noPosition");
                continue;
            }
            ids[k] = s.nftId;
            cols[k] = appliedCol;
            unchecked {
                ++k;
            }
        }

        if (k == 0) return;

        if (k < n) {
            uint256[] memory ids2 = new uint256[](k);
            uint256[] memory cols2 = new uint256[](k);
            for (uint256 j; j < k; ++j) {
                ids2[j] = ids[j];
                cols2[j] = cols[j];
            }
            lendingPool.batchUpdateCollateralValueFromOracle(ids2, cols2);
        } else {
            lendingPool.batchUpdateCollateralValueFromOracle(ids, cols);
        }

        for (uint256 i; i < n; ++i) {
            Snapshot calldata s = snaps[i];
            uint256 expected = snapshotNonce[s.nftId];
            (bool ok, uint256 appliedCol, ) = _validate(s, expected);
            if (!ok) continue;
            (uint256 debt, , , , ) = lendingPool.getPosition(s.nftId);
            if (debt == 0) continue;

            unchecked {
                snapshotNonce[s.nftId]++;
            }
            lastAppliedEpoch[s.nftId] = s.epochId;
            lastGoodCollateralWad[s.nftId] = appliedCol;
            emit SnapshotApplied(s.nftId, appliedCol, s.epochId, s.greenfieldContentHash);
        }
    }
}

project/contracts/OracleManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./interfaces/IOracleRegistry.sol";

/**
 * @title OracleManager
 * @notice Multi-provider yield/uptime oracle with median consensus, staleness TTL, optional outlier rejection,
 *         and explicit failure signaling for upstream lending risk engines.
 *
 * TRUST: Provider addresses are allow-listed; submissions are untrusted until consensus + freshness checks pass.
 *        A single provider cannot move consensus when `minProvidersForConsensus` > 1.
 *
 * GOVERNANCE (§14.5): whitelist / quorum / outlier policy changes require `GOVERNOR_ROLE` (Timelock).
 * `GUARDIAN_ROLE` may only trip the circuit breaker (fast incident response). Recovery is timelocked governance.
 */
contract OracleManager is AccessControl, IOracleRegistry {
    bytes32 public constant ORACLE_PROVIDER_ROLE = keccak256("ORACLE_PROVIDER_ROLE");
    bytes32 public constant GOVERNOR_ROLE = keccak256("GOVERNOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    uint256 public constant MAX_STALENESS = 1 hours;
    uint256 public constant MAX_DEVIATION_BPS = 2000;
    uint256 public constant MAX_SUBMISSIONS_PER_DEVICE = 50;
    uint256 public constant PROVIDER_COOLDOWN = 30 seconds;
    /// @notice TTL for `getConsensusYield` / `isConsensusFresh` (wall clock after last successful consensus).
    uint256 public constant CONSENSUS_TTL = 24 hours;

    /// @notice If true, submissions that deviate too far from prior consensus revert (strict mode).
    bool public rejectOutlierSubmissions;
    /// @notice Minimum distinct fresh submissions required to publish consensus (production: >= 2).
    uint256 public minProvidersForConsensus;

    bool public circuitBreakerTripped;
    /// @notice When consensus cannot be formed from fresh submissions, flag degraded (monitoring).
    bool public lastConsensusFailed;

    struct OracleData {
        uint256 yieldValue;
        uint256 uptimeScore;
        uint256 timestamp;
        address provider;
    }

    struct DeviceOracle {
        OracleData[] submissions;
        uint256 consensusYield;
        uint256 consensusUptime;
        uint256 lastConsensusTime;
        uint256 earningsHistoryHash;
        uint256 submissionHead;
    }

    mapping(uint256 => DeviceOracle) public deviceOracles;
    mapping(address => bool) public activeProviders;
    mapping(address => uint256) public lastSubmissionTime;
    uint256 public providerCount;

    event OracleSubmission(uint256 indexed nftId, address indexed provider, uint256 yieldValue, uint256 uptime);
    event OracleSubmissionRejected(uint256 indexed nftId, address indexed provider, string reason);
    event ConsensusReached(uint256 indexed nftId, uint256 consensusYield, uint256 consensusUptime, uint256 freshProviders);
    event OracleConsensusFailed(uint256 indexed nftId, uint256 freshCount, uint256 requiredMin);
    event OracleStale(uint256 indexed nftId, uint256 lastConsensusTime, uint256 ttl);
    event AnomalyDetected(uint256 indexed nftId, address indexed provider, string reason);
    event CircuitBreakerTripped(address indexed triggeredBy, string reason);
    event CircuitBreakerReset(address indexed admin);
    /// @dev Monitoring aliases (§16.4 / §16.10) — same actions as circuit breaker, explicit for indexers.
    event OracleFrozen(address indexed triggeredBy, string reason);
    event OracleRecovered(address indexed admin);
    event OracleFallbackActivated(uint256 indexed nftId, string reason);
    event RejectOutlierSubmissionsUpdated(bool reject);
    event MinProvidersForConsensusUpdated(uint256 minProviders);
    event OracleProviderListUpdated(address indexed provider, bool active, uint256 providerCountAfter);

    error CircuitBreakerActive();
    error OutlierRejected();
    error InvalidUptime();
    error InvalidYield();
    error CooldownActive();

    constructor(address admin) {
        address a = admin == address(0) ? msg.sender : admin;
        _grantRole(DEFAULT_ADMIN_ROLE, a);
        _grantRole(GOVERNOR_ROLE, a);
        _grantRole(GUARDIAN_ROLE, a);
        rejectOutlierSubmissions = true;
        minProvidersForConsensus = 1;
    }

    function isOracleProviderActive(address provider) external view override returns (bool) {
        return activeProviders[provider];
    }

    modifier whenNotTripped() {
        if (circuitBreakerTripped) revert CircuitBreakerActive();
        _;
    }

    function setRejectOutlierSubmissions(bool reject) external onlyRole(GOVERNOR_ROLE) {
        rejectOutlierSubmissions = reject;
        emit RejectOutlierSubmissionsUpdated(reject);
    }

    function setMinProvidersForConsensus(uint256 minProviders) external onlyRole(GOVERNOR_ROLE) {
        require(minProviders > 0, "min 1");
        minProvidersForConsensus = minProviders;
        emit MinProvidersForConsensusUpdated(minProviders);
    }

    function tripCircuitBreaker(string calldata reason) external onlyRole(GUARDIAN_ROLE) {
        circuitBreakerTripped = true;
        emit CircuitBreakerTripped(msg.sender, reason);
    }

    function resetCircuitBreaker() external onlyRole(GOVERNOR_ROLE) {
        circuitBreakerTripped = false;
        emit CircuitBreakerReset(msg.sender);
    }

    function addProvider(address provider) external onlyRole(GOVERNOR_ROLE) {
        require(provider != address(0), "Zero address");
        require(!activeProviders[provider], "Already active");
        _grantRole(ORACLE_PROVIDER_ROLE, provider);
        activeProviders[provider] = true;
        providerCount++;
        emit OracleProviderListUpdated(provider, true, providerCount);
    }

    function removeProvider(address provider) external onlyRole(GOVERNOR_ROLE) {
        require(activeProviders[provider], "Not active");
        _revokeRole(ORACLE_PROVIDER_ROLE, provider);
        activeProviders[provider] = false;
        providerCount--;
        emit OracleProviderListUpdated(provider, false, providerCount);
    }

    function submitData(
        uint256 nftId,
        uint256 yieldValue,
        uint256 uptimeScore,
        bytes calldata /* reserved attestation */
    ) external onlyRole(ORACLE_PROVIDER_ROLE) whenNotTripped {
        if (uptimeScore > 10000) revert InvalidUptime();
        if (yieldValue == 0) revert InvalidYield();
        if (block.timestamp < lastSubmissionTime[msg.sender] + PROVIDER_COOLDOWN) revert CooldownActive();

        lastSubmissionTime[msg.sender] = block.timestamp;
        DeviceOracle storage o = deviceOracles[nftId];

        if (o.consensusYield > 0) {
            uint256 deviation = yieldValue > o.consensusYield
                ? ((yieldValue - o.consensusYield) * 10000) / o.consensusYield
                : ((o.consensusYield - yieldValue) * 10000) / o.consensusYield;

            if (deviation > MAX_DEVIATION_BPS) {
                emit AnomalyDetected(nftId, msg.sender, "yield deviation");
                if (rejectOutlierSubmissions) {
                    emit OracleSubmissionRejected(nftId, msg.sender, "outlier");
                    revert OutlierRejected();
                }
            }
        }

        OracleData memory entry = OracleData({
            yieldValue: yieldValue,
            uptimeScore: uptimeScore,
            timestamp: block.timestamp,
            provider: msg.sender
        });

        if (o.submissions.length < MAX_SUBMISSIONS_PER_DEVICE) {
            o.submissions.push(entry);
        } else {
            o.submissions[o.submissionHead % MAX_SUBMISSIONS_PER_DEVICE] = entry;
            o.submissionHead++;
        }

        emit OracleSubmission(nftId, msg.sender, yieldValue, uptimeScore);
        _computeConsensus(nftId);
    }

    /// @notice Many devices in one tx — one provider cooldown check, lower per-device overhead on BSC/opBNB.
    function submitDataBatch(
        uint256[] calldata nftIds,
        uint256[] calldata yieldValues,
        uint256[] calldata uptimeScores
    ) external onlyRole(ORACLE_PROVIDER_ROLE) whenNotTripped {
        uint256 n = nftIds.length;
        require(n == yieldValues.length && n == uptimeScores.length, "len");
        if (block.timestamp < lastSubmissionTime[msg.sender] + PROVIDER_COOLDOWN) revert CooldownActive();
        lastSubmissionTime[msg.sender] = block.timestamp;

        for (uint256 i; i < n; ++i) {
            uint256 nftId = nftIds[i];
            uint256 yieldValue = yieldValues[i];
            uint256 uptimeScore = uptimeScores[i];
            if (uptimeScore > 10000) revert InvalidUptime();
            if (yieldValue == 0) revert InvalidYield();

            DeviceOracle storage o = deviceOracles[nftId];

            if (o.consensusYield > 0) {
                uint256 deviation = yieldValue > o.consensusYield
                    ? ((yieldValue - o.consensusYield) * 10000) / o.consensusYield
                    : ((o.consensusYield - yieldValue) * 10000) / o.consensusYield;

                if (deviation > MAX_DEVIATION_BPS) {
                    emit AnomalyDetected(nftId, msg.sender, "yield deviation");
                    if (rejectOutlierSubmissions) {
                        emit OracleSubmissionRejected(nftId, msg.sender, "outlier");
                        revert OutlierRejected();
                    }
                }
            }

            OracleData memory entry = OracleData({
                yieldValue: yieldValue,
                uptimeScore: uptimeScore,
                timestamp: block.timestamp,
                provider: msg.sender
            });

            if (o.submissions.length < MAX_SUBMISSIONS_PER_DEVICE) {
                o.submissions.push(entry);
            } else {
                o.submissions[o.submissionHead % MAX_SUBMISSIONS_PER_DEVICE] = entry;
                o.submissionHead++;
            }

            emit OracleSubmission(nftId, msg.sender, yieldValue, uptimeScore);
            _computeConsensus(nftId);
        }
    }

    function _computeConsensus(uint256 nftId) internal {
        DeviceOracle storage o = deviceOracles[nftId];
        uint256 len = o.submissions.length;
        uint256[] memory freshYields = new uint256[](len);
        uint256[] memory freshUptimes = new uint256[](len);
        uint256 freshCount = 0;

        for (uint256 i = 0; i < len; i++) {
            if (block.timestamp - o.submissions[i].timestamp <= MAX_STALENESS) {
                freshYields[freshCount] = o.submissions[i].yieldValue;
                freshUptimes[freshCount] = o.submissions[i].uptimeScore;
                freshCount++;
            }
        }

        if (freshCount >= minProvidersForConsensus) {
            _sort(freshYields, freshCount);
            _sort(freshUptimes, freshCount);

            o.consensusYield = freshYields[freshCount / 2];
            o.consensusUptime = freshUptimes[freshCount / 2];
            o.lastConsensusTime = block.timestamp;
            lastConsensusFailed = false;

            emit ConsensusReached(nftId, o.consensusYield, o.consensusUptime, freshCount);
        } else {
            lastConsensusFailed = true;
            emit OracleConsensusFailed(nftId, freshCount, minProvidersForConsensus);
            emit OracleFallbackActivated(nftId, "no_consensus");
        }
    }

    function _sort(uint256[] memory arr, uint256 len) internal pure {
        for (uint256 i = 1; i < len; i++) {
            uint256 key = arr[i];
            uint256 j = i;
            while (j > 0 && arr[j - 1] > key) {
                arr[j] = arr[j - 1];
                j--;
            }
            arr[j] = key;
        }
    }

    function getConsensusYield(uint256 nftId)
        external
        view
        returns (uint256 yield_, uint256 uptime, uint256 timestamp)
    {
        DeviceOracle storage o = deviceOracles[nftId];
        require(o.lastConsensusTime > 0, "no consensus");
        if (block.timestamp - o.lastConsensusTime > CONSENSUS_TTL) revert("stale consensus");
        return (o.consensusYield, o.consensusUptime, o.lastConsensusTime);
    }

    function isConsensusFresh(uint256 nftId) external view returns (bool) {
        return block.timestamp - deviceOracles[nftId].lastConsensusTime <= CONSENSUS_TTL;
    }

    /// @dev Backward-compatible alias for indexers.
    function isDataFresh(uint256 nftId) external view returns (bool) {
        return block.timestamp - deviceOracles[nftId].lastConsensusTime <= CONSENSUS_TTL;
    }

    function getSubmissionCount(uint256 nftId) external view returns (uint256) {
        return deviceOracles[nftId].submissions.length;
    }
}

project/contracts/RevenueRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./RevenueTypes.sol";
import "./interfaces/ITreasuryHub.sol";

/**
 * @title RevenueRouter
 * @notice Collects protocol fees from the lending pool, attributes revenue by source,
 *         and splits proceeds across LP yield, treasury (or `TreasuryHub`), MACH stakers, insurance, and growth.
 *         Supports a governance-toggled conservative (stress) split that prioritizes LPs and insurance.
 */
contract RevenueRouter is AccessControl, ReentrancyGuard {
    using SafeERC20 for IERC20;

    bytes32 public constant GOVERNANCE_ROLE = keccak256("GOVERNANCE_ROLE");
    bytes32 public constant FEE_REPORTER_ROLE = keccak256("FEE_REPORTER_ROLE");

    /// @notice Minimum LP share in normal mode (solvency bias).
    uint16 public constant MIN_LP_BPS_NORMAL = 2500;
    /// @notice Minimum insurance share in normal mode.
    uint16 public constant MIN_INSURANCE_BPS_NORMAL = 800;
    /// @notice Minimum LP share in conservative (stress) mode.
    uint16 public constant MIN_LP_BPS_STRESS = 3500;
    /// @notice Minimum insurance share in conservative mode.
    uint16 public constant MIN_INSURANCE_BPS_STRESS = 1500;
    /// @notice Hard cap on growth tranche in normal mode (anti-mercenary emissions).
    uint16 public constant MAX_GROWTH_BPS_NORMAL = 1500;

    IERC20 public immutable asset;

    address public lpRecipient;
    address public treasuryRecipient;
    address public stakerRecipient;
    address public insuranceRecipient;
    address public growthRecipient;

    /// @notice If set, treasury tranche is pulled into `TreasuryHub` for categorized accounting; else `treasuryRecipient`.
    address public treasuryHub;

    struct AllocationBps {
        uint16 lp;
        uint16 treasury;
        uint16 staker;
        uint16 insurance;
        uint16 growth;
    }

    AllocationBps public allocation;
    AllocationBps public stressAllocation;
    bool public conservativeRevenueMode;

    /// @notice High-level buckets for treasury flywheel narrative when treasury is not using `TreasuryHub`.
    struct TreasuryBucketBps {
        uint16 protocolRevenue;
        uint16 reserveCapital;
        uint16 operational;
        uint16 incentives;
        uint16 insuranceBackstop;
    }

    TreasuryBucketBps public treasuryBuckets;

    mapping(RevenueSource => uint256) public revenueBySource;

    uint256 public attributedToLP;
    uint256 public attributedToTreasury;
    uint256 public attributedToStakers;
    uint256 public attributedToInsurance;
    uint256 public attributedToGrowth;

    event FeeRouted(
        RevenueSource indexed src,
        uint256 grossAmount,
        uint256 toLp,
        uint256 toTreasury,
        uint256 toStakers,
        uint256 toInsurance,
        uint256 toGrowth
    );
    /// @dev Same payload as `FeeRouted`; emitted for analytics pipelines that index `FeeDistributed`.
    event FeeDistributed(
        RevenueSource indexed src,
        uint256 grossAmount,
        uint256 toLp,
        uint256 toTreasury,
        uint256 toStakers,
        uint256 toInsurance,
        uint256 toGrowth
    );
    event FeeRouteUpdated(
        address lp,
        address treasury,
        address staker,
        address insurance,
        address growth,
        address treasuryHub
    );
    event FeeParameterUpdated(bool conservativeMode, uint16 lp, uint16 treasury, uint16 staker, uint16 insurance, uint16 growth);
    event StressAllocationUpdated(uint16 lp, uint16 treasury, uint16 staker, uint16 insurance, uint16 growth);
    event ConservativeRevenueModeUpdated(bool enabled);
    event TreasuryHubUpdated(address hub);
    event RecipientsUpdated(address lp, address treasury, address staker, address insurance, address growth);
    event AllocationUpdated(uint16 lp, uint16 treasury, uint16 staker, uint16 insurance, uint16 growth);
    event TreasuryBucketsUpdated(
        uint16 protocolRevenue,
        uint16 reserveCapital,
        uint16 operational,
        uint16 incentives,
        uint16 insuranceBackstop
    );

    constructor(
        address _asset,
        address admin,
        address _lp,
        address _treasury,
        address _staker,
        address _insurance,
        address _growth
    ) {
        require(_asset != address(0) && admin != address(0), "RevenueRouter: zero");
        require(_lp != address(0) && _treasury != address(0), "RevenueRouter: recipients");
        require(_staker != address(0) && _insurance != address(0) && _growth != address(0), "RevenueRouter: recipients");
        asset = IERC20(_asset);
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(GOVERNANCE_ROLE, admin);
        lpRecipient = _lp;
        treasuryRecipient = _treasury;
        stakerRecipient = _staker;
        insuranceRecipient = _insurance;
        growthRecipient = _growth;
        allocation = AllocationBps(3500, 2800, 2200, 1000, 500);
        stressAllocation = AllocationBps(4000, 2200, 800, 2500, 500);
        treasuryBuckets = TreasuryBucketBps(3000, 3500, 1500, 1000, 1000);
    }

    function _validateNormalAllocation(AllocationBps memory a) internal pure {
        require(uint256(a.lp) + a.treasury + a.staker + a.insurance + a.growth == 10000, "RevenueRouter: bps sum");
        require(a.lp >= MIN_LP_BPS_NORMAL && a.insurance >= MIN_INSURANCE_BPS_NORMAL, "RevenueRouter: safety floor");
        require(a.growth <= MAX_GROWTH_BPS_NORMAL, "RevenueRouter: growth cap");
    }

    function _validateStressAllocation(AllocationBps memory a) internal pure {
        require(uint256(a.lp) + a.treasury + a.staker + a.insurance + a.growth == 10000, "RevenueRouter: bps sum");
        require(a.lp >= MIN_LP_BPS_STRESS && a.insurance >= MIN_INSURANCE_BPS_STRESS, "RevenueRouter: stress floor");
    }

    function setRecipients(
        address _lp,
        address _treasury,
        address _staker,
        address _insurance,
        address _growth
    ) external onlyRole(GOVERNANCE_ROLE) {
        require(_lp != address(0) && _treasury != address(0), "RevenueRouter: zero");
        require(_staker != address(0) && _insurance != address(0) && _growth != address(0), "RevenueRouter: zero");
        lpRecipient = _lp;
        treasuryRecipient = _treasury;
        stakerRecipient = _staker;
        insuranceRecipient = _insurance;
        growthRecipient = _growth;
        emit RecipientsUpdated(_lp, _treasury, _staker, _insurance, _growth);
        emit FeeRouteUpdated(_lp, _treasury, _staker, _insurance, _growth, treasuryHub);
    }

    function setTreasuryHub(address hub) external onlyRole(GOVERNANCE_ROLE) {
        if (treasuryHub != address(0)) {
            asset.safeApprove(treasuryHub, 0);
        }
        treasuryHub = hub;
        if (hub != address(0)) {
            asset.safeApprove(hub, type(uint256).max);
        }
        emit TreasuryHubUpdated(hub);
        emit FeeRouteUpdated(lpRecipient, treasuryRecipient, stakerRecipient, insuranceRecipient, growthRecipient, hub);
    }

    function setAllocation(uint16 lp, uint16 treasury, uint16 staker, uint16 insurance, uint16 growth) external onlyRole(GOVERNANCE_ROLE) {
        AllocationBps memory a = AllocationBps(lp, treasury, staker, insurance, growth);
        _validateNormalAllocation(a);
        allocation = a;
        emit AllocationUpdated(lp, treasury, staker, insurance, growth);
        emit FeeParameterUpdated(conservativeRevenueMode, lp, treasury, staker, insurance, growth);
    }

    function setStressAllocation(uint16 lp, uint16 treasury, uint16 staker, uint16 insurance, uint16 growth) external onlyRole(GOVERNANCE_ROLE) {
        AllocationBps memory a = AllocationBps(lp, treasury, staker, insurance, growth);
        _validateStressAllocation(a);
        stressAllocation = a;
        emit StressAllocationUpdated(lp, treasury, staker, insurance, growth);
        AllocationBps memory eff = conservativeRevenueMode ? stressAllocation : allocation;
        emit FeeParameterUpdated(
            conservativeRevenueMode,
            eff.lp,
            eff.treasury,
            eff.staker,
            eff.insurance,
            eff.growth
        );
    }

    function setConservativeRevenueMode(bool enabled) external onlyRole(GOVERNANCE_ROLE) {
        conservativeRevenueMode = enabled;
        emit ConservativeRevenueModeUpdated(enabled);
        AllocationBps memory eff = enabled ? stressAllocation : allocation;
        emit FeeParameterUpdated(enabled, eff.lp, eff.treasury, eff.staker, eff.insurance, eff.growth);
    }

    function setTreasuryBuckets(
        uint16 protocolRevenue,
        uint16 reserveCapital,
        uint16 operational,
        uint16 incentives,
        uint16 insuranceBackstop
    ) external onlyRole(GOVERNANCE_ROLE) {
        require(
            uint256(protocolRevenue) + reserveCapital + operational + incentives + insuranceBackstop == 10000,
            "RevenueRouter: bps"
        );
        treasuryBuckets = TreasuryBucketBps(protocolRevenue, reserveCapital, operational, incentives, insuranceBackstop);
        emit TreasuryBucketsUpdated(protocolRevenue, reserveCapital, operational, incentives, insuranceBackstop);
    }

    function _effectiveAllocation() internal view returns (AllocationBps memory) {
        return conservativeRevenueMode ? stressAllocation : allocation;
    }

    /**
     * @notice Pull `amount` from caller (typically LendingPool) and split across recipients.
     */
    function routeFee(RevenueSource src, uint256 amount) external nonReentrant onlyRole(FEE_REPORTER_ROLE) {
        if (amount == 0) return;
        asset.safeTransferFrom(msg.sender, address(this), amount);
        revenueBySource[src] += amount;

        AllocationBps memory a = _effectiveAllocation();
        uint256 toLp = (amount * a.lp) / 10000;
        uint256 toTreasury = (amount * a.treasury) / 10000;
        uint256 toStakers = (amount * a.staker) / 10000;
        uint256 toInsurance = (amount * a.insurance) / 10000;
        uint256 toGrowth = amount - toLp - toTreasury - toStakers - toInsurance;

        if (toLp > 0) {
            attributedToLP += toLp;
            asset.safeTransfer(lpRecipient, toLp);
        }
        if (toTreasury > 0) {
            attributedToTreasury += toTreasury;
            if (treasuryHub != address(0)) {
                ITreasuryHub(treasuryHub).creditFromRouter(toTreasury);
            } else {
                asset.safeTransfer(treasuryRecipient, toTreasury);
            }
        }
        if (toStakers > 0) {
            attributedToStakers += toStakers;
            asset.safeTransfer(stakerRecipient, toStakers);
        }
        if (toInsurance > 0) {
            attributedToInsurance += toInsurance;
            asset.safeTransfer(insuranceRecipient, toInsurance);
        }
        if (toGrowth > 0) {
            attributedToGrowth += toGrowth;
            asset.safeTransfer(growthRecipient, toGrowth);
        }

        emit FeeRouted(src, amount, toLp, toTreasury, toStakers, toInsurance, toGrowth);
        emit FeeDistributed(src, amount, toLp, toTreasury, toStakers, toInsurance, toGrowth);
    }

    function getTreasuryBucketLabels() external view returns (TreasuryBucketBps memory) {
        return treasuryBuckets;
    }

    function getEffectiveAllocation() external view returns (AllocationBps memory) {
        return _effectiveAllocation();
    }
}

